import { initConversation, submitAnswer, uploadAsset } from './chat-api.js';

const questions = [
    {
        id: "q1",
        text: "请描述你送礼物的对象是一个怎样的人？（性格、爱好、独特的习惯等）",
        type: "text",
        placeholder: "他是一个阳光开朗、热爱音乐的男孩..."
    },
    {
        id: "q2",
        text: "你希望这份礼物给TA带来怎样的感受或影响？",
        type: "text",
        placeholder: "我希望这份礼物能让他感受到被理解和被爱..."
    },
    {
        id: "q3",
        text: "有没有什么特别的颜色、元素或风格是你希望融入到这个网页设计中的？",
        type: "text",
        placeholder: "我喜欢蓝色和星空元素，希望风格是赛博朋克..."
    },
    {
        id: "q4",
        text: "请上传一张对他/她有特殊意义的图片，这张图片将作为网页的背景元素之一。",
        type: "image",
        placeholder: "上传一张照片"
    },
    {
        id: "q5",
        text: "你有什么想对TA说的话？这段话将作为最终礼物页面上的专属留言。",
        type: "text",
        placeholder: "亲爱的，感谢你一直以来的陪伴..."
    },
];

let currentStep = 0;
let answers = JSON.parse(localStorage.getItem('chatAnswers')) || {};
let conversationId = localStorage.getItem('conversationId') || null;

const questionTextElement = document.getElementById('question-text');
const userInputElement = document.getElementById('user-input');
const uploadImageButton = document.getElementById('upload-image-button');
const fileInputElement = document.getElementById('file-input');
const prevButton = document.getElementById('prev-button');
const nextButton = document.getElementById('next-button');
const currentStepElement = document.getElementById('current-step');
const totalStepsElement = document.getElementById('total-steps');
const chatOverlay = document.querySelector('.chat-overlay');

totalStepsElement.textContent = questions.length;

async function loadConversation() {
    if (!conversationId) {
        const data = await initConversation();
        conversationId = data.conversationId;
        localStorage.setItem('conversationId', conversationId);
    }
    renderQuestion();
}

function renderQuestion() {
    const question = questions[currentStep];
    questionTextElement.textContent = question.text;
    userInputElement.value = answers[question.id] || '';
    userInputElement.placeholder = question.placeholder;

    if (question.type === "image") {
        userInputElement.style.display = "none";
        uploadImageButton.style.display = "block";
    } else {
        userInputElement.style.display = "block";
        uploadImageButton.style.display = "none";
    }

    prevButton.disabled = currentStep === 0;
    nextButton.disabled = !answers[question.id] && question.type !== "image"; // Disable next if no answer for text type

    currentStepElement.textContent = currentStep + 1;
    chatOverlay.style.display = 'none'; // Hide overlay by default
}

function saveAnswer() {
    const question = questions[currentStep];
    if (question.type === "text") {
        answers[question.id] = userInputElement.value;
    }
    localStorage.setItem('chatAnswers', JSON.stringify(answers));
}

async function goToNextStep() {
    saveAnswer();
    const question = questions[currentStep];
    // Submit answer to API if it's a text type
    if (question.type === "text" && answers[question.id]) {
        await submitAnswer(conversationId, question.id, answers[question.id]);
    }

    if (currentStep < questions.length - 1) {
        currentStep++;
        renderQuestion();
    } else {
        alert("所有问题已回答！即将前往礼物页面。");
        window.location.href = './gift.html';
    }
}

function goToPrevStep() {
    saveAnswer();
    if (currentStep > 0) {
        currentStep--;
        renderQuestion();
    }
}

userInputElement.addEventListener('input', () => {
    // Enable next button as soon as there's some input for text type
    if (questions[currentStep].type === "text") {
        nextButton.disabled = !userInputElement.value;
    }
});

nextButton.addEventListener('click', goToNextStep);
prevButton.addEventListener('click', goToPrevStep);

uploadImageButton.addEventListener('click', () => {
    fileInputElement.click();
});

fileInputElement.addEventListener('change', async (event) => {
    const file = event.target.files[0];
    if (file) {
        chatOverlay.style.display = 'flex'; // Show overlay during upload
        questionTextElement.textContent = "图片上传中，请稍候...";
        try {
            const response = await uploadAsset(conversationId, file);
            if (response.success) {
                answers[questions[currentStep].id] = response.assetUrl;
                localStorage.setItem('chatAnswers', JSON.stringify(answers));
                alert("图片上传成功！");
                goToNextStep();
            } else {
                alert("图片上传失败！");
                chatOverlay.style.display = 'none';
                questionTextElement.textContent = questions[currentStep].text;
            }
        } catch (error) {
            console.error("Error uploading image:", error);
            alert("图片上传失败！");
            chatOverlay.style.display = 'none';
            questionTextElement.textContent = questions[currentStep].text;
        }
    }
});

loadConversation();